// FVE Heating Control v2.0 ÔÇö Kompletn├ş ┼Ö├şzen├ş topen├ş domu
// ┼ś├şd├ş: NIBE (47371), ob─Ťhov├ę ─Źerpadlo, patrony (3 f├íze), baz├ęnov├Ż ventil, chlazen├ş

var config = global.get("fve_config") || {};
var prices = global.get("fve_prices_forecast") || [];

// === HELPER ===
function getState(id) {
    var e = global.get("homeassistant.homeAssistant.states['" + id + "']") || {};
    return e.state;
}
function getFloat(id, def) {
    var v = parseFloat(getState(id));
    return isNaN(v) ? (def || 0) : v;
}
function getBool(id) { return getState(id) === "on"; }

// Najdi nejlevn─Ťj┼í├ş budouc├ş hodinu (do konce sol├írn├ş v├Żroby nebo do r├ína)
function hasCheaperHourAhead(prices, currentHour, currentLevel) {
    for (var i = 0; i < prices.length; i++) {
        var h = prices[i].hour;
        var m = prices[i].minute || 0;
        if (m !== 0) continue;
        // Budouc├ş hodiny (po aktu├íln├ş)
        if (h <= currentHour) continue;
        var futureLevel = prices[i].levelCheapestHourBuy || 99;
        if (futureLevel < currentLevel) return true;
    }
    return false;
}

// === PARAMETRY Z CONFIGU ===
var MIN_TANK = config.topeni_min_teplota_nadrze || 30;
var MAX_TANK = config.topeni_max_teplota_nadrze || 50;
var NOCNI_SNIZ = config.topeni_nocni_snizeni || 0.5;
var NOCNI_OD = config.topeni_nocni_od || 22;
var NOCNI_DO = config.topeni_nocni_do || 6;
var NOUZ_TEMP = config.topeni_nouzova_teplota || 18;
var MIN_PRETOK = config.topeni_min_pretok_patron_w || 3000;
var PATRON_W = config.topeni_patron_faze_w || 3000;
var MIN_SOC_PAT = config.topeni_min_soc_patron || 90;
var MAX_TANK_PAT = getFloat("input_number.topeni_max_teplota_patron", config.topeni_max_teplota_patron || 53);
var PRAH_DRAHA = config.prah_draha_energie || 12;
var BEZPECNY_POKLES = config.topeni_bezpecny_pokles || 0.7;
var HYSTEREZE_CHLAZENI = config.topeni_hystereze_chlazeni || 1.0;
var SOLAR_FORECAST_THRESHOLD = config.topeni_solar_forecast_kwh || 30;
var solarForecastTomorrow = getFloat("input_number.predpoved_solarni_vyroby_zitra", 0);
var bigSolarTomorrow = solarForecastTomorrow >= SOLAR_FORECAST_THRESHOLD;
var letniRezim = config.letni_rezim === true;

// === ─îTEN├Ź STAV┼« ===
var automatizace = getBool("input_boolean.automatizovat_topeni");
var targetTemp = getFloat("input_number.nastavena_teplota_v_dome", 22);
var indoorTemp = getFloat("sensor.hp2551ae_pro_v2_1_0_indoor_temperature", 20);
var outdoorTemp = getFloat("sensor.hp2551ae_pro_v2_1_0_outdoor_temperature", 10);
var tankTemp = getFloat("sensor.teplota_smesovac_teplota", 35);
var dm = getFloat("sensor.nibe_degree_minutes", 0);
var batSoc = getFloat("sensor.battery_percent", 50);
var prebytek = getFloat("sensor.fve_dostupny_prebytek", 0);
var compressor = getBool("binary_sensor.nibe_kompresory_aktivni_binarni");
var pumpState = getState("sensor.nibe_aktualni_realny_stav") || "";
var fireplace = getBool("input_boolean.topi_se_v_krbu");
var coolEnabled = getBool("input_boolean.chlazeni");
var autoHlad = getBool("input_boolean.auto_ma_hlad");
var autoNabiji = global.get("auto_nabijeni_aktivni") || false;  // wallbox fyzicky nabiji
var ultraLevna = global.get("ultra_levna_energie") || false;  // ultra-levny rezim (cena < 1 Kc + solar hodiny)

var nibeOn = getBool("switch.nibe_topeni");
var obehOn = getBool("switch.horousany_termostat_prizemi_kote");
var p1on = getBool("switch.patrona_faze_1");
var p2on = getBool("switch.patrona_faze_3_2");
var p3on = getBool("switch.patrona_faze_3");
var ventilOn = getBool("switch.bazen_ventil_smesovac");
var coolOn = getBool("switch.nibe_chlazeni");

var hour = new Date().getHours();
var now = Date.now();
var NIBE_COOLDOWN_MS = (config.nibe_cooldown_min || 10) * 60 * 1000;  // min doba mezi NIBE p┼Öepnut├şmi
var lastNibeSwitch = flow.get("last_nibe_switch") || 0;
var nibeCooldownOk = (now - lastNibeSwitch) >= NIBE_COOLDOWN_MS;

// === GRID LOST ===
var gridLostRaw = getFloat("sensor.grid_lost_ciselny", 0);
var gridLost = gridLostRaw >= 2;  // 0=OK, 1=Warning, 2=Grid Lost
var solarPower = getFloat("sensor.vyroba_fve", 0);  // aktu├íln├ş sol├írn├ş v├Żkon (W)
var NIBE_PEAK_W = config.nibe_peak_w || 14000;  // peak odb─Ťr NIBE

// === SOL├üRN├Ź HODINY ===
var plan = global.get("fve_plan") || {};
var solarStart = (plan && plan.solarStartHour) || 9;
var solarEnd = (plan && plan.solarEndHour) || 17;
var isSolarHour = (hour >= solarStart && hour < solarEnd);
var solarHoursLeft = isSolarHour ? (solarEnd - hour) : 0;
var SOLAR_MARGIN_HOURS = config.topeni_solar_margin_hours || 2;

// === CENOV├Ł LEVEL (v┼żdy cel├í hodina, minute=0) ===
var lvl = 99;
for (var i = 0; i < prices.length; i++) {
    if (prices[i].hour === hour && (prices[i].minute === 0 || prices[i].minute === undefined)) {
        lvl = prices[i].levelCheapestHourBuy || 99;
        break;
    }
}
// Fallback: pokud se aktu├íln├ş hodina nena┼íla v prices (po restartu NR nebo midnight edge case)
if (lvl === 99) {
    lvl = getFloat("input_number.levelcheapesthourbuy", 12);
}
var isDraha = lvl >= PRAH_DRAHA;

// === NO─îN├Ź RE┼ŻIM ===
var isNight = (hour >= NOCNI_OD || hour < NOCNI_DO);
// No─Źn├ş sn├ş┼żen├ş = hystereze pro drah├ę hodiny (v levn├Żch topit na plnou teplotu)
var effTarget = isNight ? (targetTemp - NOCNI_SNIZ) : targetTemp;

// === PATRONY STATE ===
var actPat = (p1on ? 1 : 0) + (p2on ? 1 : 0) + (p3on ? 1 : 0);
var availPat = prebytek + actPat * PATRON_W;

// === OCHRANA ===
var pumpWorking = pumpState.indexOf("Klidov├Ż") === -1 && pumpState !== "";
var canOffNibe = !compressor && !pumpWorking;
var canOnNibe = nibeCooldownOk;

// === ROZHODOV├üN├Ź ===
var actions = [];
var reason = "";
var patTarget = 0;
var shutdownDone = flow.get("shutdown_done") || false;

if (!automatizace) {
    // AUTOMATIZACE OFF ÔÇö manu├íln├ş m├│d dle input_select.topeni_mod
    // Flow NEP┼śEPISUJE mod ÔÇö jen prov├íd├ş p┼Ö├şkazy dle manu├íln─Ť nastaven├ęmo modu
    var manualMod = getState("input_select.topeni_mod") || "Vypnuto";
    flow.set("topeni_mod_active", manualMod);  // sync flow state s HA entitou

    if (manualMod === "Vypnuto") {
        // Manu├íln├ş VYPNUTO ÔÇö ┼ż├ídn├ę z├ísahy, u┼żivatel ovl├íd├í v┼íe s├ím
        reason = "Manu├íln├ş mod: VYPNUTO ÔÇö bez z├ísah┼» automatizace";

    } else if (manualMod === "NIBE") {
        // Manualní NIBE – uživatel řídí NIBE přímo, automatizace NEZASAHUJE do NIBE
        // Pouze patrony zablokujeme (bezpečnost)
        if (p1on) actions.push("p1_off");
        if (p2on) actions.push("p2_off");
        if (p3on) actions.push("p3_off");
        reason = "Manuální mod: NIBE – bez zásahů do NIBE | indoor=" + indoorTemp.toFixed(1) + "°C";

    } else if (manualMod === "Patrony") {
        // Manu├íln├ş PATRONY ÔÇö topit jen z patron, NIBE blokov├íno
        // NIBE: nezasahovat – uživatel kontroluje
        var tankOk = tankTemp >= MIN_TANK;
        var patronyMohou = batSoc >= MIN_SOC_PAT && !autoHlad && !autoNabiji && tankTemp < MAX_TANK_PAT && (!gridLost || solarPower > 0);
        // Hlavn├ş loop zap├şn├í patrony POUZE pokud actPat === 0.
        // Pokud patrony b─Ť┼ż├ş (actPat > 0), 5s smy─Źka ┼Ö├şd├ş po─Źet f├íz├ş.
        if (patronyMohou && actPat === 0) {
            if (availPat >= MIN_PRETOK * 3)      { patTarget = 3; }
            else if (availPat >= MIN_PRETOK * 2) { patTarget = 2; }
            else if (availPat >= MIN_PRETOK)     { patTarget = 1; }
        } else if (patronyMohou && actPat > 0) {
            // Patrony b─Ť┼ż├ş ÔÇö 5s smy─Źka ┼Ö├şd├ş
            patTarget = actPat;
        }
        // patronyMohou === false Ôćĺ hlavn├ş loop vypne f├íze
        var p1want = patTarget >= 1;
        var p2want = patTarget >= 2;
        var p3want = patTarget >= 3;
        if (p1want !== p1on) actions.push(p1want ? "p1_on" : "p1_off");
        if (p2want !== p2on) actions.push(p2want ? "p2_on" : "p2_off");
        if (p3want !== p3on) actions.push(p3want ? "p3_on" : "p3_off");
        reason = "Manu├íln├ş mod: PATRONY | p┼Öebytek=" + Math.round(availPat) + "W f├íze=" + patTarget;

    } else if (manualMod === "Obehove") {
        // Manualní OBEHOVE – oběhové čerpadlo, NIBE nezasahovat
        // Patrony zastavit
        if (p1on) actions.push("p1_off");
        if (p2on) actions.push("p2_off");
        if (p3on) actions.push("p3_off");
        var tankOk = tankTemp >= MIN_TANK;
        var needsHeat = indoorTemp < effTarget;
        if (tankOk && needsHeat && !obehOn) {
            actions.push("obehove_on");
            reason = "Manu├íln├ş mod: OB─ÜHOV├ë ÔÇö ON";
        } else if ((!tankOk || !needsHeat) && obehOn) {
            actions.push("obehove_off");
            reason = "Manu├íln├ş mod: OB─ÜHOV├ë ÔÇö OFF";
        } else {
            reason = "Manu├íln├ş mod: OB─ÜHOV├ë | n├ídr┼ż=" + tankTemp.toFixed(1) + "┬░C";
        }
    }

    // Zapi┼í aktu├íln├ş manu├íln├ş mod do global (pro HA input_select update)
    global.set("topeni_mod", manualMod);

} else {
    var forceStart = flow.get("shutdown_done") === true;  // pr├ív─Ť zapnuta automatizace
    flow.set("shutdown_done", false);
    // Reset summer flag pokud se zm─Ťn├ş automatizace
    if (letniRezim) {
        // LETN├Ź RE┼ŻIM ÔÇö jednor├ízov├ę nastaven├ş default stavu, pak jen chlazen├ş
        var summerDone = flow.get("summer_setup_done") || false;
        if (!summerDone) {
            // Jednor├ízov─Ť: NIBE on (pro TUV), ob─Ťhov├ę off, patrony off
            if (canOffNibe) actions.push("nibe_on");
            if (obehOn) actions.push("obehove_off");
            if (p1on) actions.push("p1_off");
            if (p2on) actions.push("p2_off");
            if (p3on) actions.push("p3_off");
            flow.set("summer_setup_done", true);
            reason = "L├ęto ÔÇö jednor├ízov├ę nastaven├ş default";
        }

        // Chlazen├ş ÔÇö b─Ť┼ż├ş st├íle v l├ęt─Ť
        if (coolEnabled) {
            if (!coolOn && indoorTemp > effTarget + HYSTEREZE_CHLAZENI) {
                actions.push("cool_on");
                reason = "Chlazen├ş ON (" + indoorTemp.toFixed(1) + ">" + (effTarget+HYSTEREZE_CHLAZENI).toFixed(1) + "┬░C)";
            } else if (coolOn && indoorTemp < effTarget) {
                actions.push("cool_off");
                reason = "Chlazen├ş OFF (" + indoorTemp.toFixed(1) + "<" + effTarget.toFixed(1) + "┬░C)";
            } else {
                reason = "L├ęto | " + indoorTemp.toFixed(1) + "/" + effTarget.toFixed(1) + "┬░C" + (coolOn ? " | Chlazen├ş" : "");
            }
        } else {
            if (coolOn) actions.push("cool_off");
            reason = "L├ęto | chlazen├ş vypnuto";
        }
    } else {
        // ZIMN├Ź RE┼ŻIM
        flow.set("summer_setup_done", false);

        // 1. Baz├ęnov├Ż ventil - kontrola
        if (ventilOn) actions.push("ventil_off");

        // 2. Chlazen├ş OFF v zim─Ť
        if (coolOn) actions.push("cool_off");

        // 3. TOP├ëN├Ź MOD ÔÇö vz├íjemn├í exkluzivita NIBE a patrony
        // MOD_PATRONY Ôćĺ NIBE blokov├íno. MOD_NIBE Ôćĺ patrony blokov├íny.
        var topeniModAktivni = flow.get("topeni_mod_active") || "Vypnuto";

        // Podm├şnky pro topen├ş
        var tankOk = tankTemp >= MIN_TANK;
        var needsHeat = indoorTemp < effTarget;

        // Podm├şnky pro spu┼ít─Ťn├ş patrony (sol├írn├ş p┼Öebytek)
        // Ultra levn├í: relaxace - ni┼ż┼í├ş SOC pr├íh, patrony mohou br├ít ze s├şt─Ť, auto neblokuje
        var ultraSocPrah = ultraLevna ? (config.min_soc || 20) : MIN_SOC_PAT;
        var patronyMohou = batSoc >= ultraSocPrah && (ultraLevna || (!autoHlad && !autoNabiji)) && tankTemp < MAX_TANK_PAT && (!gridLost || solarPower > 0);
        var patronyActive = false;
        // Hlavn├ş loop zap├şn├í patrony POUZE pokud actPat === 0 (prvn├ş zapnut├ş nebo restart).
        // Jakmile patrony jednou b─Ť┼ż├ş, 5s smy─Źka (pat_korekce_func) p┼Öeb├şr├í ┼Ö├şzen├ş po─Źtu f├íz├ş.
        if (patronyMohou && actPat === 0) {
            // Patrony neb─Ť┼ż├ş ÔÇö konzervativn├ş start: v┼żdy jen 1 f├íze, korekce (5s) p┼Öid├í dal┼í├ş
            // Ultra levn├í: patrony mohou startovat i bez sol├írn├şho p┼Öebytku (grid je levn├Ż)
            if (ultraLevna || availPat >= MIN_PRETOK) {
                patTarget = 1; patronyActive = true;
                // Nastav cooldown pro korekci ÔÇö ─Źekat ne┼ż se syst├ęm stabilizuje po startu
                flow.set("pat_change_cooldown", 6); // 6├Ś5s = 30s
            }
        } else if (patronyMohou && actPat > 0) {
            // Patrony b─Ť┼ż├ş ÔÇö 5s smy─Źka ┼Ö├şd├ş, hlavn├ş loop jen zaznamen├í stav
            patTarget = actPat;
            patronyActive = true;
        }
        // patronyMohou === false Ôćĺ hlavn├ş loop vypne f├íze (podm├şnky nespln─Ťny)

        // P┼Öep├şn├ín├ş modu ÔÇö patrony POUZE pokud teplota je bl├şzko c├şle (max 0.2┬░C pod)
        // Patrony = POSLEDN├Ź priorita ÔÇö p┼Öebytky co nem├ím kam d├ít (auto, NIBE, baterie)
        // Velk├Ż rozd├şl teploty Ôćĺ NIBE (topen├ş domu). Mal├Ż rozd├şl + p┼Öebytek Ôćĺ patrony (oh┼Öev n├ídr┼że).
        var PATRON_TEMP_MARGIN = 0.3;  // ┬░C ÔÇö max rozd├şl indoor vs target pro patrony
        var tempGap = effTarget - indoorTemp;  // kladn├ę = pod c├şlem
        if (isSolarHour && tempGap <= PATRON_TEMP_MARGIN && needsHeat) {
            // Sol├írn├ş hodiny + teplota bl├şzko c├şle (ÔëĄ 0.3┬░C pod) Ôćĺ mod Patrony
            // ─îek├í se na SOC Ôëą 95%, pak se patrony spust├ş. NIBE blokov├íno.
            topeniModAktivni = "Patrony";
        } else if (tempGap > PATRON_TEMP_MARGIN && needsHeat) {
            // Velk├Ż rozd├şl ÔÇö d┼»m pot┼Öebuje topit p┼Öes NIBE
            topeniModAktivni = "NIBE";
        } else if (!needsHeat && patronyActive) {
            // Teplota dosa┼żena + patrony b─Ť┼ż├ş Ôćĺ patrony d├íl oh┼Ö├şvaj├ş n├ídr┼ż
            topeniModAktivni = "Patrony";
        } else if (!needsHeat) {
            topeniModAktivni = "Vypnuto";
        } else {
            // Fallback: needsHeat + ne sol├írn├ş hodiny Ôćĺ NIBE
            topeniModAktivni = "NIBE";
        }
        flow.set("topeni_mod_active", topeniModAktivni);

        // Blokace dle modu
        var nibeBlockedByMod     = (topeniModAktivni === "Patrony");
        var patronyBlockedByMod  = (topeniModAktivni === "NIBE");

        // Patrony ON/OFF (blokovan├ę pokud MOD_NIBE)
        // Pokud patrony u┼ż b─Ť┼ż├ş (actPat > 0), f├íze ┼Ö├şd├ş korekce (5s) ÔÇö hlavn├ş loop jen startuje/stopuje
        var korekceRidi = actPat > 0 && patronyMohou;
        var p1want = !patronyBlockedByMod && patTarget >= 1;
        var p2want = !patronyBlockedByMod && patTarget >= 2;
        var p3want = !patronyBlockedByMod && patTarget >= 3;
        if (!korekceRidi) {
            if (p1want !== p1on) actions.push(p1want ? "p1_on" : "p1_off");
            if (p2want !== p2on) actions.push(p2want ? "p2_on" : "p2_off");
            if (p3want !== p3on) actions.push(p3want ? "p3_on" : "p3_off");
        }

        // 4. NIBE ┼Ö├şzen├ş (blokov├íno pokud MOD_PATRONY)
        var nibeBlockedByPatrony = nibeBlockedByMod;
        var nibeBlockDischarge = true;
        var safeTemp = effTarget - BEZPECNY_POKLES;
        var gridAllowNibe = !gridLost || (gridLost && solarPower >= NIBE_PEAK_W);  // bezpe─Źn├Ż pr├íh: effTarget - 0.7┬░C (v noci ni┼ż┼í├ş d├şky NOCNI_SNIZ)
        var cheaperAhead = hasCheaperHourAhead(prices, hour, lvl);

        // === PRIORITA: TOPEN├Ź > AUTO NAB├ŹJEN├Ź ===
        // Pokud NIBE pot┼Öebuje topit a auto nab├şj├ş Ôćĺ auto MUS├Ź zastavit (topen├ş m├í p┼Öednost)
        // NIBE se NEBLOKUJE kv┼»li autu ÔÇö topen├ş je prioritn├ş
        // (auto blokace se ┼Öe┼í├ş p┼Öes cerpadlo_topi v manager-nabijeni-auta)
        // Pokud auto nab├şj├ş a NIBE zap├şn├í topen├ş Ôćĺ po┼íli akci stop_auto_nabijeni
        // Ultra levna: NIBE a auto mohou bezet soucasne (blokace pada)
        if (!ultraLevna && autoNabiji && needsHeat && !nibeBlockedByPatrony) {
            actions.push("stop_auto_nabijeni");
        }

        // Grid Lost ochrana ÔÇö NIBE jen pokud sol├ír sta─Ź├ş na peak
        if (!gridAllowNibe) {
            // Grid Lost + nedostatek sol├íru Ôćĺ NIBE OFF
            if (nibeOn && canOffNibe) actions.push("nibe_off");
        } else if (fireplace) {
            // Krb aktivn├ş Ôćĺ NIBE OFF (krb nah┼Ö├şv├í n├ídr┼ż m├şsto NIBE)
            if (nibeOn && canOffNibe) actions.push("nibe_off");
        } else if (tankTemp > MAX_TANK) {
            // N├ídr┼ż p┼Öeh┼Ö├ít├í (> MAX_TANK) Ôćĺ NIBE OFF
            if (nibeOn && canOffNibe) actions.push("nibe_off");
        } else if (nibeBlockedByPatrony) {
            // Patrony aktivn├ş nebo fyzicky zapnut├ę Ôćĺ NIBE OFF + zablokovat nibe_on (bezpe─Źnost jisti─Źe)
            if (nibeOn && canOffNibe) actions.push("nibe_off");
        } else if (needsHeat && !isDraha) {
            // LEVN├ü/ST┼śEDN├Ź HODINA + pot┼Öeba topit
            var SOLAR_OVERRIDE_W = config.topeni_solar_override_w || 8000;
            if (bigSolarTomorrow && indoorTemp >= safeTemp && !(isSolarHour && batSoc > 90)) {
                // Velk├Ż solar z├ştra + teplota bezpe─Źn├í Ôćĺ NIBE OFF, ┼íet┼Ö├şme pro sol├írn├ş hodiny
                // V├Żjimka: v sol├írn├şch hodin├ích p┼Öi SOC > 90% topit ze sol├íru + baterie
                if (nibeOn && canOffNibe) actions.push("nibe_off");
            } else if (cheaperAhead && indoorTemp >= safeTemp && !(isSolarHour && batSoc > 90)) {
                // Teplota bezpe─Źn├í + levn─Ťj┼í├ş hodiny existuj├ş Ôćĺ PO─îKAT
                // V├Żjimka: v sol├írn├şch hodin├ích p┼Öi SOC > 90% topit hned
                if (nibeOn && canOffNibe) actions.push("nibe_off");
            } else if (prebytek >= SOLAR_OVERRIDE_W) {
                // Velk├Ż sol├írn├ş p┼Öebytek Ôćĺ NIBE ON bez blokace vyb├şjen├ş
                if (!nibeOn) actions.push("nibe_on");
                nibeBlockDischarge = false;
            } else {
                // Pot┼Öeba topit a nem├í smysl ─Źekat Ôćĺ NIBE ON
                // SOC > 90%: topit ze sol├íru + baterie (bez blokace vyb├şjen├ş)
                if (!nibeOn) actions.push("nibe_on");
                nibeBlockDischarge = (batSoc <= 90);
            }
        } else if (needsHeat && isDraha && nibeOn) {
            // DRAH├ü HODINA + NIBE U┼Ż B─Ü┼Ż├Ź Ôćĺ pokra─Źovat, ale odblokovat vyb├şjen├ş
            // (sol├ír + baterie kryj├ş spot┼Öebu, nekupovat drahou energii ze s├şt─Ť)
            nibeBlockDischarge = false;
        } else if (needsHeat && isDraha && !nibeOn) {
            // DRAH├ü HODINA + NIBE NESPOU┼áT─ÜT p┼Öi mal├ęm sol├íru
            var SOLAR_OVERRIDE_W = config.topeni_solar_override_w || 8000;
            if (prebytek >= SOLAR_OVERRIDE_W) {
                // Velk├Ż p┼Öebytek i v drah├ę hodin─Ť Ôćĺ NIBE ON bez blokace
                actions.push("nibe_on");
                nibeBlockDischarge = false;
            } else if (indoorTemp < safeTemp) {
                // Nouzov─Ť: teplota pod bezpe─Źn├Żm prahem Ôćĺ NIBE ON
                actions.push("nibe_on");
            }
            // Jinak: ─Źekat na levn─Ťj┼í├ş hodiny nebo v─Ťt┼í├ş sol├ír
        } else if (!needsHeat) {
            // Nepot┼Öebuje topit Ôćĺ NIBE OFF
            if (nibeOn && canOffNibe) actions.push("nibe_off");
        }

        // Ulo┼żit info o blokaci vyb├şjen├ş pro NIBE
        flow.set("nibe_block_discharge", nibeBlockDischarge);

        // 5. Ob─Ťhov├ę ─Źerpadlo (p┼Öi krbu NESAHAT - ┼Ö├şd├ş jin├í automatika)
        // Ob─Ťhov├ę je nez├ívisl├ę na NIBE ÔÇö ─Źerp├í teplo z n├ídr┼że do domu kdykoli n├ídr┼ż m├í co d├ít
        // bigSolarTomorrow omezen├ş se t├Żk├í jen NIBE, ne ob─Ťhov├ęho (ob─Ťhov├ę spot┼Öebuje minimum)
        if (!fireplace) {
            // No─Źn├ş sn├ş┼żen├ş: ob─Ťhov├ę nespou┼ít─Ťt pokud teplota neklesla pod targetTemp - NOCNI_SNIZ
            var obehoveTarget = isNight ? (targetTemp - NOCNI_SNIZ) : effTarget;
            var needsHeatObehove = indoorTemp < obehoveTarget;
            if (tankOk && needsHeatObehove) {
                actions.push("obehove_on");
            } else {
                // N├ídr┼ż vychladl├í nebo teplota v noci OK Ôćĺ ─Źerpadlo off
                if (obehOn) actions.push("obehove_off");
            }
        }

        // Reason
        var parts = [];
        parts.push(isDraha ? "DRAH├ü(Lv" + lvl + ")" : "Lv" + lvl);
        parts.push("In:" + indoorTemp.toFixed(1) + "/" + effTarget.toFixed(1) + "┬░C");
        parts.push("Tank:" + tankTemp.toFixed(0) + "┬░C");
        parts.push("DM:" + Math.round(dm));
        parts.push("Out:" + outdoorTemp.toFixed(0) + "┬░C");
        if (patronyActive) parts.push("PAT:" + patTarget + "f(" + Math.round(availPat) + "W)");
        if (fireplace) parts.push("KRB");
        if (isNight) parts.push("NOC");
        if (ultraLevna) parts.push("ULTRA_LEVNA");
        if (gridLost) parts.push("ÔÜíGRID_LOST");
        if (isSolarHour) parts.push("ÔśÇ" + solarHoursLeft + "h");
        if (cheaperAhead) parts.push("LEVN─ÜJ┼á├ŹÔćô");
        if (bigSolarTomorrow) parts.push("ÔśÇZ:" + Math.round(solarForecastTomorrow) + "kWh");
        parts.push("Safe:" + safeTemp.toFixed(1) + "┬░C");
        if (!nibeBlockDischarge) parts.push("NoBLK");
        reason = parts.join(" | ");
    }
}

// === OCHRANA: NIBE nelze vypnout pokud pracuje ===
if (actions.indexOf("nibe_off") > -1 && !canOffNibe) {
    actions = actions.filter(function(a) { return a !== "nibe_off"; });
    reason += " ÔÜá´ŞĆOCHRANA:NIBE pracuje";
}

// === OCHRANA: nikdy nibe_on + nibe_off z├írove┼ł ===
var hasNibeOn = actions.indexOf("nibe_on") > -1;
var hasNibeOff = actions.indexOf("nibe_off") > -1;
if (hasNibeOn && hasNibeOff) {
    // Konflikt ÔÇö ponechat aktu├íln├ş stav (nic ned─Ťlat)
    actions = actions.filter(function(a) { return a !== "nibe_on" && a !== "nibe_off"; });
    reason += " ÔÜá´ŞĆKONFLIKT:on+offÔćĺskip";
}

// === COOLDOWN: min doba mezi NIBE p┼Öepnut├şmi (p┼Öesko─Źit p┼Öi forceStart) ===
if ((hasNibeOn && !nibeOn) || (hasNibeOff && nibeOn && canOffNibe)) {
    if (!nibeCooldownOk && !forceStart) {
        actions = actions.filter(function(a) { return a !== "nibe_on" && a !== "nibe_off"; });
        reason += " ÔĆ│COOLDOWN";
    } else {
        flow.set("last_nibe_switch", now);
    }
}

// === FIN├üLN├Ź BEZPE─îNOSTN├Ź POJISTKA: NIBE a patrony nikdy sou─Źasn─Ť ===
var hasNibeOnFinal = actions.indexOf("nibe_on") > -1;
var hasPatOnFinal = actions.indexOf("p1_on") > -1 || actions.indexOf("p2_on") > -1 || actions.indexOf("p3_on") > -1;
var patronyRunning = p1on || p2on || p3on;
if (hasNibeOnFinal && (hasPatOnFinal || patronyRunning)) {
    actions = actions.filter(function(a) { return a !== "nibe_on"; });
    reason += " ÔÜá´ŞĆMUTEX:NIBE blokov├íno patronami";
}
if (hasPatOnFinal && nibeOn) {
    actions = actions.filter(function(a) { return a !== "p1_on" && a !== "p2_on" && a !== "p3_on"; });
    reason += " ÔÜá´ŞĆMUTEX:patrony blokov├íny NIBE";
}

// === TOPEN├Ź MOD: zapsat do global pro HA input_select ===
// topeniModAktivni je undefined pokud automatizace=OFF Ôćĺ pou┼ż├şt manualMod nebo "Vypnuto"
var finalTopeniMod = (typeof topeniModAktivni !== "undefined" && topeniModAktivni) ? topeniModAktivni : (global.get("topeni_mod") || "Vypnuto");
global.set("topeni_mod", finalTopeniMod);

// === GLOBAL: cerpadlo_topi pro FVE blokaci ===
var isHeating = pumpState.indexOf("Vyt├íp─Ťn├ş") > -1;
var isTUV = pumpState.indexOf("Oh┼Öev vody") > -1 || pumpState.indexOf("TUV") > -1;
// Pokud NIBE b─Ť┼ż├ş s velk├Żm sol├írn├şm ziskem, NEBLOKOVAT vyb├şjen├ş baterie
var nibeBlkDisch = flow.get("nibe_block_discharge") !== false;  // default true
global.set("cerpadlo_topi", (isHeating || isTUV) && nibeBlkDisch);

// === STATUS ===
var st = [];
st.push(automatizace ? (letniRezim ? "L├ëTO" : "ZIMA") : "OFF");
st.push(indoorTemp.toFixed(1) + "/" + effTarget.toFixed(1) + "┬░C");
st.push("Tank:" + tankTemp.toFixed(0));
st.push("Lv" + lvl);
if (actions.length > 0) st.push("Ôćĺ" + actions.join(","));

var color = "green";
if (!automatizace) color = "grey";
else if (indoorTemp < NOUZ_TEMP) color = "red";
else if (isDraha || patTarget > 0) color = "yellow";
node.status({fill: color, shape: "dot", text: st.join(" | ")});

// === OUTPUT ===
// O1: actions array Ôćĺ router switch
// O2: debug/status
var actionMsgs = null;
if (actions.length > 0) {
    actionMsgs = actions.map(function(a) { return {action: a}; });
}
var statusMsg = {
    payload: {
        automatizace: automatizace, letniRezim: letniRezim,
        indoorTemp: indoorTemp, targetTemp: effTarget,
        tankTemp: tankTemp, dm: dm, outdoorTemp: outdoorTemp,
        priceLevel: lvl, isDraha: isDraha, isNight: isNight,
        nibeOn: nibeOn, obehOn: obehOn, patrony: actPat, patTarget: patTarget,
        fireplace: fireplace, batSoc: batSoc, prebytek: prebytek,
        actions: actions, reason: reason
    }
};
return [actionMsgs, statusMsg];

// Detekce topen├ş vs chlazen├ş ÔÇö blokace vyb├şjen├ş baterie
var state = msg.payload || "";
var isHeating = state.indexOf("Vyt├íp─Ťn├ş") > -1;
var isTUV = state.indexOf("Oh┼Öev vody") > -1 || state.indexOf("TUV") > -1;
var blockDischarge = isHeating || isTUV;
msg.blockDischarge = blockDischarge;
var txt = blockDischarge
    ? "Blokace (" + (isHeating ? "topen├ş" : "TUV") + ")"
    : "OK - " + state.substring(0, 30);
node.status({fill: blockDischarge ? "yellow" : "green", shape: "dot", text: txt});
return msg;

// Re┼żim nep┼Ö├ştomnosti ÔÇö sn├ş┼żen├ş teploty kdy┼ż nejsme doma
var config = global.get("fve_config") || {};
var AWAY_TEMP = config.topeni_teplota_nepritomnost || 21;
var letniRezim = config.letni_rezim === true;

function getState(id) {
    var e = global.get("homeassistant.homeAssistant.states['" + id + "']") || {};
    return e.state;
}
function getFloat(id, def) {
    var v = parseFloat(getState(id));
    return isNaN(v) ? (def || 0) : v;
}

var jsme_doma = getState("input_boolean.jsme_doma") === "on";
var currentTemp = getFloat("input_number.nastavena_teplota_v_dome", 22);
var savedTemp = flow.get("away_saved_temp");

if (!jsme_doma && !letniRezim) {
    // Odchod z domu v zim─Ť Ôćĺ sn├ş┼żit teplotu
    if (currentTemp > AWAY_TEMP) {
        // Ulo┼żit aktu├íln├ş teplotu jen pokud jsme ji je┼ít─Ť neulo┼żili
        if (!savedTemp || savedTemp <= AWAY_TEMP) {
            flow.set("away_saved_temp", currentTemp);
        }
        node.status({fill:"yellow", shape:"dot", text:"PRY─î Ôćĺ " + AWAY_TEMP + "┬░C (ulo┼żeno " + currentTemp + "┬░C)"});
        return {payload: AWAY_TEMP};
    } else {
        node.status({fill:"yellow", shape:"ring", text:"PRY─î | teplota u┼ż " + currentTemp + "┬░C"});
        return null;
    }
} else if (jsme_doma && savedTemp && savedTemp > AWAY_TEMP) {
    // P┼Ö├şchod dom┼» Ôćĺ obnovit ulo┼żenou teplotu
    var restoreTemp = savedTemp;
    flow.set("away_saved_temp", null);
    node.status({fill:"green", shape:"dot", text:"DOMA Ôćĺ " + restoreTemp + "┬░C (obnoveno)"});
    return {payload: restoreTemp};
} else {
    node.status({fill:"grey", shape:"ring", text: jsme_doma ? "DOMA" : (letniRezim ? "L├ëTO" : "PRY─î")});
    return null;
}

// Patrony korekce v2.3
// ┼ś├şd├ş po─Źet aktivn├şch f├íz├ş pokud patrony b─Ť┼ż├ş (cyklus 5s).
//
// SENZORY:
// sensor.nabijeni_baterii: kladn├ę = baterie se NAB├ŹJ├Ź, z├íporn├ę = VYB├ŹJ├Ź
// sensor.nabijeni_baterii_minus: kladn├ę = baterie VYB├ŹJ├Ź (v┼żdy >= 0)
//
// SOC LOGIKA:
// SOC < 90%: patrony STOP (┼Öe┼í├ş hlavn├ş loop)
// SOC 90-95%: NO-DRAIN ÔÇö baterie se NESM├Ź vyb├şjet!
//   - battMinus > 0 Ôćĺ OKAM┼ŻIT─Ü ubrat f├ízi
//   - battCharging > 500W (p┼Öebytek nab├şj├ş baterii) Ôćĺ po stable p┼Öidat f├ízi
// SOC >= 95%: FORCE-DRAIN ÔÇö baterie se NESM├Ź nab├şjet! max_charge_power=0
//   - battCharging > 100 (baterie se st├íle nab├şj├ş) Ôćĺ p┼Öidat f├ízi agresivn─Ť
//   - battMinus > DRAIN_W (1000W) Ôćĺ vyb├şj├ş moc Ôćĺ ubrat f├ízi
//
// OUTPUT 1: [{action},...] Ôćĺ patron router
// OUTPUT 2: {payload: {value: N}} Ôćĺ max_charge_power service

function getState(id) {
    var e = global.get("homeassistant.homeAssistant.states['" + id + "']") || {};
    return e.state;
}
function getFloat(id, def) {
    var v = parseFloat(getState(id));
    return isNaN(v) ? (def || 0) : v;
}
function getBool(id) { return getState(id) === "on"; }
function chargeMsg(value) { return {payload: {value: value}}; }

// === AUTOMATIZACE OFF Ôćĺ MANU├üLN├Ź M├ôD ===
// P┼Öi automatizace=OFF: 1x vypnout v┼íechny f├íze, pak absolutn─Ť nic ned─Ťlat.
// U┼żivatel ovl├íd├í patrony ru─Źn─Ť ÔÇö flow nesm├ş zasahovat!
var automatizace = getBool("input_boolean.automatizovat_topeni");
if (!automatizace) {
    var p1off = !getBool("switch.patrona_faze_1");
    var p2off = !getBool("switch.patrona_faze_3_2");
    var p3off = !getBool("switch.patrona_faze_3");
    var allOff = p1off && p2off && p3off;
    var alreadyStopped = flow.get("pat_manual_stopped") || false;
    if (!allOff && !alreadyStopped) {
        // Patrony je┼ít─Ť b─Ť┼ż├ş Ôćĺ 1x vypnout
        flow.set("pat_manual_stopped", true);
        flow.set("pat_discharge_count", 0);
        flow.set("pat_stable_count", 0);
        flow.set("pat_change_cooldown", 0);
        var stopAll = [];
        if (!p1off) stopAll.push({action: "p1_off"});
        if (!p2off) stopAll.push({action: "p2_off"});
        if (!p3off) stopAll.push({action: "p3_off"});
        node.status({fill:"grey", shape:"ring", text:"MANUAL: 1x STOP v┼íech patrony"});
        return [stopAll, chargeMsg(-1)];
    }
    node.status({fill:"grey", shape:"ring", text:"MANUAL M├ôD ÔÇö flow nezasahuje"});
    return [null, chargeMsg(-1)];
}
// Automatizace ON Ôćĺ reset flagu
flow.set("pat_manual_stopped", false);

function makeActions(current, target, p1, p2, p3) {
    var actions = [];
    if (target > current) {
        if (target >= 1 && !p1) actions.push({action: "p1_on"});
        if (target >= 2 && !p2) actions.push({action: "p2_on"});
        if (target >= 3 && !p3) actions.push({action: "p3_on"});
    } else {
        if (target < 3 && p3) actions.push({action: "p3_off"});
        if (target < 2 && p2) actions.push({action: "p2_off"});
        if (target < 1 && p1) actions.push({action: "p1_off"});
    }
    return actions.length > 0 ? actions : null;
}

// Aktu├íln├ş stav f├íz├ş
var p1on = getBool("switch.patrona_faze_1");
var p2on = getBool("switch.patrona_faze_3_2");
var p3on = getBool("switch.patrona_faze_3");
var actPat = (p1on ? 1 : 0) + (p2on ? 1 : 0) + (p3on ? 1 : 0);

var batSoc = getFloat("sensor.battery_percent", 0);
var config = global.get("fve_config") || {};
var DRAIN_SOC_PRAH = config.topeni_patron_drain_soc_prah || 95;
var MIN_SOC_PAT = config.topeni_min_soc_patron || 90;

// max_charge_power: SOC >= 95% Ôćĺ 0 (block), jinak -1 (unlimited)
var chargePower = (batSoc >= DRAIN_SOC_PRAH) ? 0 : -1;
global.set("pat_block_charge", batSoc >= DRAIN_SOC_PRAH);
var chgMsg = chargeMsg(chargePower);

// ┼Ż├ídn├í f├íze neb─Ť┼ż├ş Ôćĺ hlavn├ş loop rozhodne
if (actPat === 0) {
    flow.set("pat_discharge_count", 0);
    flow.set("pat_stable_count", 0);
    node.status({fill:"grey", shape:"dot", text:"OFF SOC:" + batSoc + "% chg:" + chargePower});
    return [null, chgMsg];
}

// === PATRONY B─Ü┼Ż├Ź ===
var ultraLevna = global.get("ultra_levna_energie") || false;
var ultraSocPrah = ultraLevna ? (config.min_soc || 20) : MIN_SOC_PAT;

// SOC pod prahem Ôćĺ vypnout V┼áECHNY f├íze
if (batSoc < ultraSocPrah) {
    var stopActions = [];
    if (p1on) stopActions.push({action: "p1_off"});
    if (p2on) stopActions.push({action: "p2_off"});
    if (p3on) stopActions.push({action: "p3_off"});
    flow.set("pat_discharge_count", 0);
    flow.set("pat_stable_count", 0);
    node.status({fill:"red", shape:"dot", text:"SOC " + batSoc + "% < " + ultraSocPrah + "% Ôćĺ ALL OFF"});
    if (stopActions.length > 0) return [stopActions, chgMsg];
    return [null, chgMsg];
}

// Bateriov├ę senzory
// battMinus: kladn├ę = baterie VYB├ŹJ├Ź (sensor.nabijeni_baterii_minus, v┼żdy >= 0)
// battCharging: kladn├ę = baterie se NAB├ŹJ├Ź, z├íporn├ę = VYB├ŹJ├Ź (sensor.nabijeni_baterii)
var battMinus = getFloat("sensor.nabijeni_baterii_minus", 0);
var battCharging = getFloat("sensor.nabijeni_baterii", 0);

var CHANGE_COOLDOWN = config.topeni_patron_change_cooldown || 6;
var changeCooldown = flow.get("pat_change_cooldown") || 0;

// COOLDOWN ÔÇö ale p┼Öi vyb├şjen├ş v NO-DRAIN z├│n─Ť reagovat okam┼żit─Ť
if (changeCooldown > 0) {
    if (batSoc < DRAIN_SOC_PRAH && battMinus > 0 && actPat > 0) {
        // NO-DRAIN z├│na + baterie vyb├şj├ş Ôćĺ okam┼żit─Ť ubrat i v cooldownu
        var newT = actPat - 1;
        flow.set("pat_change_cooldown", CHANGE_COOLDOWN);
        flow.set("pat_stable_count", 0);
        node.status({fill:"red", shape:"dot", text:"ÔÜá´ŞĆNO-DRAINÔćô " + actPat + "Ôćĺ" + newT + "f drain=" + Math.round(battMinus) + "W SOC:" + batSoc + "%"});
        return [makeActions(actPat, newT, p1on, p2on, p3on), chgMsg];
    }
    flow.set("pat_change_cooldown", changeCooldown - 1);
    node.status({fill:"blue", shape:"ring", text:"ÔĆ│cd:" + changeCooldown + " " + actPat + "f SOC:" + batSoc + "% chgB:" + Math.round(battCharging) + "W chgP:" + chargePower});
    return [null, chgMsg];
}

// ====================================================================
// SOC 90-95%: NO-DRAIN ÔÇö baterie se NESM├Ź vyb├şjet
// ====================================================================
if (batSoc >= MIN_SOC_PAT && batSoc < DRAIN_SOC_PRAH) {
    // Baterie vyb├şj├ş (battMinus > 0) Ôćĺ OKAM┼ŻIT─Ü ubrat f├ízi
    if (battMinus > 0 && actPat > 0) {
        var newT = actPat - 1;
        flow.set("pat_change_cooldown", CHANGE_COOLDOWN);
        flow.set("pat_stable_count", 0);
        node.status({fill:"red", shape:"dot", text:"NO-DRAINÔćô " + actPat + "Ôćĺ" + newT + "f drain=" + Math.round(battMinus) + "W SOC:" + batSoc + "%"});
        return [makeActions(actPat, newT, p1on, p2on, p3on), chgMsg];
    }
    // Baterie se nab├şj├ş hodn─Ť (p┼Öebytek existuje) Ôćĺ bezpe─Źn├ę p┼Öidat f├ízi
    // battCharging > 500 = baterie se nab├şj├ş 500+W = sol├írn├ş p┼Öebytek
    var MIN_SURPLUS = 500;
    var stableCount = flow.get("pat_stable_count") || 0;
    var STABLE_CYCLES = config.topeni_patron_stable_cycles || 6;
    if (battCharging > MIN_SURPLUS && actPat < 3) {
        stableCount++;
        flow.set("pat_stable_count", stableCount);
        if (stableCount >= STABLE_CYCLES) {
            var newT = actPat + 1;
            flow.set("pat_stable_count", 0);
            flow.set("pat_change_cooldown", CHANGE_COOLDOWN);
            node.status({fill:"yellow", shape:"dot", text:"NO-DRAINÔćĹ " + actPat + "Ôćĺ" + newT + "f surplus=" + Math.round(battCharging) + "W SOC:" + batSoc + "%"});
            return [makeActions(actPat, newT, p1on, p2on, p3on), chgMsg];
        }
        node.status({fill:"green", shape:"dot", text:"NO-DRAIN " + actPat + "f chgB:+" + Math.round(battCharging) + "W (" + stableCount + "/" + STABLE_CYCLES + ") SOC:" + batSoc + "%"});
    } else {
        flow.set("pat_stable_count", 0);
        node.status({fill:"green", shape:"dot", text:"NO-DRAIN " + actPat + "f chgB:" + Math.round(battCharging) + "W SOC:" + batSoc + "%"});
    }
    return [null, chgMsg];
}

// ====================================================================
// SOC >= 95%: FORCE-DRAIN ÔÇö baterie se NESM├Ź nab├şjet, max_charge_power=0
// ====================================================================
if (batSoc >= DRAIN_SOC_PRAH) {
    // Baterie se st├íle nab├şj├ş (battCharging > 100) Ôćĺ p┼Öidat f├ízi agresivn─Ť
    if (battCharging > 100 && actPat < 3) {
        var newT = actPat + 1;
        flow.set("pat_change_cooldown", 3);
        flow.set("pat_stable_count", 0);
        node.status({fill:"yellow", shape:"dot", text:"DRAINÔćĹ " + actPat + "Ôćĺ" + newT + "f chgB:+" + Math.round(battCharging) + "W SOC:" + batSoc + "%"});
        return [makeActions(actPat, newT, p1on, p2on, p3on), chgMsg];
    }
    // Baterie vyb├şj├ş p┼Ö├şli┼í (nad DRAIN_W) Ôćĺ ubrat f├ízi
    var DRAIN_W = config.topeni_patron_drain_w || 1000;
    if (battMinus > DRAIN_W && actPat > 0) {
        var newT = actPat - 1;
        flow.set("pat_change_cooldown", CHANGE_COOLDOWN);
        flow.set("pat_stable_count", 0);
        node.status({fill:"red", shape:"dot", text:"DRAINÔćô " + actPat + "Ôćĺ" + newT + "f drain=" + Math.round(battMinus) + "W>" + DRAIN_W + " SOC:" + batSoc + "%"});
        return [makeActions(actPat, newT, p1on, p2on, p3on), chgMsg];
    }
    node.status({fill:"green", shape:"dot", text:"DRAIN " + actPat + "f chgB:" + Math.round(battCharging) + "W drain=" + Math.round(battMinus) + "W SOC:" + batSoc + "%"});
    return [null, chgMsg];
}

// Fallback
node.status({fill:"grey", shape:"ring", text:"? " + actPat + "f SOC:" + batSoc + "%"});
return [null, chgMsg];
